    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result[(name, pkg['id'])] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return result

b = extract(before)
a = extract(after)

print('CHANGES:')
for key in sorted(set(b) | set(a)):
    if key in b and key in a:
        if b[key] != a[key]:
            print(f'  {key[0]:20s} {key[1]:40s} {b[key][1]:>10s} -> {a[key][1]}')
    elif key in b:
        print(f'  {key[0]:20s} {key[1]:40s} REMOVED')
    else:
        print(f'  {key[0]:20s} {key[1]:40s} ADDED')

print()
print('UNCHANGED:')
for key in sorted(set(b) & set(a)):
    if b[key] == a[key]:
        print(f'  {key[0]:20s} {key[1]:40s} {b[key][1]}')
"

